#[unsafe(no_mangle)]
pub fn rust_main() -> ! {
    clear_bss();

    #[cfg(target_arch = "loongarch64")]
    {
        arch::enable_boot_paging();
        unsafe {
            arch::jump_to_high_half(rust_main_high as usize);
        }
    }

