/// TCP 接收/发送缓冲区默认大小（64 KiB）。
const TCP_RX_BUF_LEN: usize = 64 * 1024;
const TCP_TX_BUF_LEN: usize = 64 * 1024;
/// UDP 数据报缓冲区的元数据槽数和总字节数。
